/**
 * Resource Type Images Configuration
 * 
 * This file maps resource types to their display images.
 * All images are from Google-hosted gstatic assets.
 * 
 * To use local images instead:
 * 1. Download/save images to: frontend/public/images/
 * 2. Update the URLs to: /images/lecture-hall.jpg, etc.
 */

export const RESOURCE_TYPE_IMAGES = {
  LECTURE_HALL: {
    url: 'https://www.oberlin.edu/craig-lecture-hall',
    fallback: '🎓',
    description: 'Lecture hall'
  },
  LAB: {
    url: 'https://fonts.gstatic.com/s/i/short-term/release/materialsymbolsoutlined/science/default/48px.svg',
    fallback: '🔬',
    description: 'Laboratory'
  },
  MEETING_ROOM: {
    url: 'https://fonts.gstatic.com/s/i/short-term/release/materialsymbolsoutlined/meeting_room/default/48px.svg',
    fallback: '💼',
    description: 'Meeting room'
  },
  EQUIPMENT: {
    url: 'https://fonts.gstatic.com/s/i/short-term/release/materialsymbolsoutlined/precision_manufacturing/default/48px.svg',
    fallback: '⚙️',
    description: 'Equipment'
  },
  OUTDOOR_SPACE: {
    url: 'https://fonts.gstatic.com/s/i/short-term/release/materialsymbolsoutlined/park/default/48px.svg',
    fallback: '🌳',
    description: 'Outdoor space'
  },
  PARKING: {
    url: 'https://fonts.gstatic.com/s/i/short-term/release/materialsymbolsoutlined/local_parking/default/48px.svg',
    fallback: '🅿️',
    description: 'Parking'
  },
  OTHER: {
    url: 'https://fonts.gstatic.com/s/i/short-term/release/materialsymbolsoutlined/category/default/48px.svg',
    fallback: '📦',
    description: 'Other resource'
  }
};

/**
 * Get image URL for a resource type
 * @param {string} type - Resource type (e.g., 'LECTURE_HALL')
 * @returns {Object} - { url, fallback, description }
 */
export const getResourceTypeImage = (type) => {
  return RESOURCE_TYPE_IMAGES[type] || RESOURCE_TYPE_IMAGES.OTHER;
};

/**
 * Get all resource types with their images
 * @returns {Object} - Map of all resource types and images
 */
export const getAllResourceImages = () => {
  return RESOURCE_TYPE_IMAGES;
};
